211: ## 4. xterm.js Integration <a name="xtermjs-integration"></a>
212: 
213: xterm.js is a terminal emulator for the browser. It's the core of the portfolio's interactive terminal.
214: 
215: ### Installation
216: 
217: ```bash
218: npm install xterm @xterm/addon-fit @xterm/addon-web-links
219: ```
220: 
221: ### The Terminal Component
222: 
223: ```tsx
224: // src/components/Terminal.tsx
225: import { useEffect, useRef, useState } from 'react';
226: import type { Terminal as XTerminal } from 'xterm';
227: 
228: // ⚠️ CRITICAL: Do NOT import xterm statically at the top level.
229: // xterm requires browser APIs and will crash during SSR or build.
230: // Use dynamic imports inside useEffect instead.
231: 
232: interface TerminalProps {
233:   welcomeMessage?: string;
234: }
235: 
236: export default function Terminal({ welcomeMessage }: TerminalProps) {
237:   const terminalRef = useRef<HTMLDivElement>(null);
238:   const xtermRef = useRef<XTerminal | null>(null);
239:   const [isReady, setIsReady] = useState(false);
240: 
241:   useEffect(() => {
242:     // Dynamic import — only runs in browser
243:     let isMounted = true;
244: 
245:     async function initTerminal() {
246:       // Dynamically import xterm and addons
247:       const { Terminal } = await import('xterm');
248:       const { FitAddon } = await import('@xterm/addon-fit');
249:       const { WebLinksAddon } = await import('@xterm/addon-web-links');
250: 
251:       // Also dynamically import the CSS
252:       await import('xterm/css/xterm.css');
253: 
254:       if (!isMounted || !terminalRef.current) return;
255: 
256:       const term = new Terminal({
257:         cursorBlink: true,
258:         cursorStyle: 'block',
259:         fontFamily: '"IBM Plex Mono", "Cascadia Code", monospace',
260:         fontSize: 14,
261:         lineHeight: 1.2,
262:         theme: {
263:           background: '#0a0a0a',
264:           foreground: '#00ff41',
265:           cursor: '#00ff41',
266:           cursorAccent: '#0a0a0a',
267:           selectionBackground: '#00ff4140',
268:           // ANSI colors
269:           black: '#0a0a0a',
270:           red: '#ff5555',
271:           green: '#00ff41',
272:           yellow: '#f1fa8c',
273:           blue: '#6272a4',
274:           magenta: '#ff79c6',
275:           cyan: '#8be9fd',
276:           white: '#f8f8f2',
277:         },
278:         allowTransparency: true,
279:         scrollback: 1000,
280:       });
281: 
282:       // Load addons
283:       const fitAddon = new FitAddon();
284:       term.loadAddon(fitAddon);
285:       term.loadAddon(new WebLinksAddon());
286: 
287:       // Mount to DOM
288:       term.open(terminalRef.current);
289:       fitAddon.fit();
290: 
291:       // Handle window resize
292:       const resizeObserver = new ResizeObserver(() => {
293:         fitAddon.fit();
294:       });
295:       resizeObserver.observe(terminalRef.current);
296: 
297:       // Store reference
298:       xtermRef.current = term;
299:       setIsReady(true);
300: 
301:       // Welcome message
302:       if (welcomeMessage) {
303:         term.writeln(welcomeMessage);
304:       }
305:       term.writeln('');
306:       term.write('joel@portfolio:~$ ');
307: 
308:       // Handle input
309:       let currentLine = '';
310:       term.onKey(({ key, domEvent }) => {
311:         const char = key;
312:         
313:         if (domEvent.key === 'Enter') {
314:           term.writeln('');
315:           handleCommand(term, currentLine.trim());
316:           currentLine = '';
317:           term.write('joel@portfolio:~$ ');
318:         } else if (domEvent.key === 'Backspace') {
319:           if (currentLine.length > 0) {
320:             currentLine = currentLine.slice(0, -1);
321:             term.write('\b \b');
322:           }
323:         } else if (char.length === 1 && !domEvent.ctrlKey && !domEvent.altKey) {
324:           currentLine += char;
325:           term.write(char);
326:         }
327:       });
328: 
329:       // Cleanup
330:       return () => {
331:         isMounted = false;
332:         resizeObserver.disconnect();
333:         term.dispose();
334:       };
335:     }
336: 
337:     initTerminal();
338: 
339:     return () => {
340:       isMounted = false;
341:       xtermRef.current?.dispose();
342:     };
343:   }, []);
344: 
345:   return (
346:     <div
347:       ref={terminalRef}
348:       className="terminal-container"
349:       style={{
350:         width: '100%',
351:         height: '100%',
352:         minHeight: '400px',
353:       }}
354:     />
355:   );
356: }
357: 
358: function handleCommand(term: any, command: string) {
359:   if (!command) return;
360: 
361:   switch (command) {
362:     case 'help':
363:       term.writeln('Available commands:');
364:       term.writeln('  about     - About me');
365:       term.writeln('  skills    - Technical skills');
366:       term.writeln('  projects  - My projects');
367:       term.writeln('  contact   - Contact info');
368:       term.writeln('  clear     - Clear screen');
369:       break;
370:     case 'clear':
371:       term.clear();
372:       break;
373:     case 'about':
374:       term.writeln('Joel Thomas — CS student at VIT Chennai');
375:       term.writeln('AI/ML researcher & full-stack developer');
376:       break;
377:     default:
378:       term.writeln(`Command not found: ${command}`);
379:       term.writeln('Type "help" for available commands.');
380:   }
381: }
382: ```
383: 
384: ### Using in Astro
385: 
386: ```astro
387: ---
388: // src/pages/index.astro
389: import Layout from '../layouts/Layout.astro';
390: import LaptopShell from '../components/LaptopShell.astro';
391: import Terminal from '../components/Terminal.tsx';
392: ---
393: 
394: <Layout title="Joel Thomas — Portfolio">
395:   <LaptopShell>
396:     <!-- client:only because xterm.js needs browser APIs -->
397:     <Terminal
398:       client:only="react"
399:       welcomeMessage="Welcome to Joel's Portfolio Terminal v2.0"
400:     />
401:   </LaptopShell>
402: </Layout>
403: ```
